package com.school.controller;
import com.school.dto.StudentForm; import com.school.service.StudentService; import jakarta.validation.Valid; import org.springframework.stereotype.Controller; import org.springframework.ui.Model; import org.springframework.validation.BindingResult; import org.springframework.web.bind.annotation.*; import org.springframework.web.servlet.mvc.support.RedirectAttributes;
@Controller @RequestMapping("/admin/students") public class AdminStudentController { private final StudentService service; public AdminStudentController(StudentService s){service=s;} @GetMapping String list(@RequestParam(required=false) String q,Model m){m.addAttribute("students",service.search(q));m.addAttribute("q",q);return "admin/students";} @GetMapping("/new") String form(Model m){m.addAttribute("studentForm",new StudentForm());return "admin/student-form";} @PostMapping String create(@Valid @ModelAttribute StudentForm studentForm,BindingResult errors,RedirectAttributes flash){if(errors.hasErrors())return "admin/student-form";service.create(studentForm);flash.addFlashAttribute("success","Student registered successfully.");return "redirect:/admin/students";} @PostMapping("/{id}/delete") String delete(@PathVariable Long id,RedirectAttributes flash){service.delete(id);flash.addFlashAttribute("success","Student removed.");return "redirect:/admin/students";} }
